import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import { fetchProducts } from "../services/api";
import logo from "../assets/logo.png";

const CATEGORIES = [
  "Todas",
  "Cepillos",
  "Pastas dentales",
  "Hilo dental",
  "Blanqueadores",
  "Enjuague bucal",
  "Otros",
];

const styles = {
  page: { minHeight: "100vh", background: "#f0f9ff" },
  carousel: { height: "500px", position: "relative" },
  overlay: {
    position: "absolute",
    inset: 0,
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    justifyContent: "center",
    color: "white",
    background: "rgba(0,0,0,0.35)",
    textAlign: "center",
  },
  container: { maxWidth: "1100px", margin: "auto", padding: "2rem" },
  grid: {
    display: "grid",
    gridTemplateColumns: "repeat(auto-fill,minmax(260px,1fr))",
    gap: "1.5rem",
  },
  card: {
    background: "white",
    borderRadius: "12px",
    overflow: "hidden",
    boxShadow: "0 2px 12px rgba(0,0,0,0.08)",
    display: "flex",
    flexDirection: "column",
  },
  img: { height: "180px", objectFit: "cover" },
  body: {
    padding: "1rem",
    display: "flex",
    flexDirection: "column",
    gap: "0.5rem",
  },
  btn: {
    padding: "0.7rem",
    border: "none",
    background: "#32d5d5",
    color: "white",
    borderRadius: "8px",
    cursor: "pointer",
    fontWeight: "700",
  },
  cartFloat: {
    position: "absolute",
    top: 20,
    right: 20,
    background: "white",
    padding: "0.7rem 1rem",
    borderRadius: "30px",
    cursor: "pointer",
    fontWeight: "700",
  },
  modalBg: {
    position: "fixed",
    inset: 0,
    background: "rgba(0,0,0,0.5)",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
  },
  modal: {
    background: "white",
    width: "100%",
    maxWidth: "520px",
    padding: "1.5rem",
    borderRadius: "12px",
  },
  row: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    marginBottom: "0.5rem",
  },
  qtyBtn: {
    padding: "4px 10px",
    margin: "0 4px",
    cursor: "pointer",
  },
};

export default function Store() {
  const [products, setProducts] = useState([]);
  const [filtered, setFiltered] = useState([]);
  const [cart, setCart] = useState([]);
  const [showCart, setShowCart] = useState(false);
  const [activeCategory, setActiveCategory] = useState("Todas");

  const navigate = useNavigate();

  useEffect(() => {
    fetchProducts().then((res) => {
      setProducts(res.data || []);
      setFiltered(res.data || []);
    });
  }, []);

  const addToCart = (p) => {
    setCart((prev) => {
      const ex = prev.find((i) => i.id === p.id);
      if (ex) {
        return prev.map((i) => (i.id === p.id ? { ...i, qty: i.qty + 1 } : i));
      }
      return [...prev, { ...p, qty: 1 }];
    });

    setShowCart(true);
  };

  const changeQty = (id, delta) => {
    setCart((prev) =>
      prev
        .map((i) => (i.id === id ? { ...i, qty: i.qty + delta } : i))
        .filter((i) => i.qty > 0),
    );
  };

  const total = cart.reduce((s, i) => s + i.qty * i.price, 0);
  const count = cart.reduce((s, i) => s + i.qty, 0);

  return (
    <div style={styles.page}>
      <div style={styles.carousel}>
        <div style={styles.overlay}>
          <img src={logo} style={{ width: 300 }} />
          <h1>Tu salud importa</h1>
        </div>

        {count > 0 && (
          <div style={styles.cartFloat} onClick={() => setShowCart(true)}>
            🛒 {count} | ${total.toFixed(2)}
          </div>
        )}
      </div>

      <div style={styles.container}>
        <div style={styles.grid}>
          {filtered.map((p) => (
            <div key={p.id} style={styles.card}>
              <img src={p.imageUrl} style={styles.img} />

              <div style={styles.body}>
                <h4>{p.name}</h4>
                <p>${p.price}</p>

                <button style={styles.btn} onClick={() => addToCart(p)}>
                  Agregar
                </button>
              </div>
            </div>
          ))}
        </div>
      </div>

      {showCart && (
        <div style={styles.modalBg} onClick={() => setShowCart(false)}>
          <div style={styles.modal} onClick={(e) => e.stopPropagation()}>
            <h3>Carrito</h3>

            {cart.map((i) => (
              <div key={i.id} style={styles.row}>
                <div>
                  {i.name}
                  <div>
                    <button
                      onClick={() => changeQty(i.id, -1)}
                      style={styles.qtyBtn}
                    >
                      -
                    </button>
                    {i.qty}
                    <button
                      onClick={() => changeQty(i.id, 1)}
                      style={styles.qtyBtn}
                    >
                      +
                    </button>
                  </div>
                </div>

                <div>${(i.qty * i.price).toFixed(2)}</div>
              </div>
            ))}

            <h4>Total: ${total.toFixed(2)}</h4>

            <button
              style={styles.btn}
              onClick={() => navigate("/checkout", { state: { cart } })}
            >
              Pagar ahora
            </button>
          </div>
        </div>
      )}
    </div>
  );
}
